import { Component } from '@angular/core';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent {

}
<h2>Hola inframundo 👽</h2>

<p>{{ fecha | date }}</p>

<section id="section">
    <article>Nuevo registro</article>
    <article>Lista registros</article>
</section>
